import{_ as e,o as t,c as a,O as r}from"./chunks/framework.bdcb0ee1.js";const u=JSON.parse('{"title":"Word Filters","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/word-filters.md","filePath":"administration/config/word-filters.md","lastUpdated":1773166765000}'),o={name:"administration/config/word-filters.md"},i=r('<h1 id="word-filters" tabindex="-1">Word Filters <a class="header-anchor" href="#word-filters" aria-label="Permalink to &quot;Word Filters&quot;">​</a></h1><p>Word filters let you automatically replace specific words or phrases in posts and messages across your board.</p><p>This is a simple string replacement system — filters match exact words only. There is no support for pattern matching or wildcards.</p><p>You can access the filter settings from the <strong>Board Config</strong> section of the Admin Control Panel.</p><h2 id="adding-a-filter" tabindex="-1">Adding a Filter <a class="header-anchor" href="#adding-a-filter" aria-label="Permalink to &quot;Adding a Filter&quot;">​</a></h2><p>To add a new filter, provide:</p><ul><li><strong>Text to replace</strong>: The word or phrase you want to block.</li><li><strong>Replacement</strong>: What the word should be replaced with. This can be another word or a censored version (e.g. <code>****</code>)</li></ul><img width="1942" height="471" alt="image" src="https://github.com/user-attachments/assets/3144217e-75a4-419c-8c7c-471932f00515"><p>Filters apply automatically to all new content posted by users, including forum posts, private messages, and topic titles.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Filters are applied after BBCode parsing.</li><li>Filters apply globally across the entire board.</li><li>You can update or remove filters at any time.</li></ul>',11),s=[i];function l(n,d,c,p,h,f){return t(),a("div",null,s)}const g=e(o,[["render",l]]);export{u as __pageData,g as default};
